--
-- Name: importar_perguntas_abertas(text); Type: PROCEDURE; Schema: public; Owner: postgres
--

CREATE PROCEDURE public.importar_perguntas_abertas(IN p_caminho_arquivo text)
    LANGUAGE plpgsql
    AS $$
BEGIN
    -- 1. Criar/Limpar tabela temporária
    -- (Nota: Tabelas temporárias em procedures duram a sessão, 
    -- mas aqui garantimos que esteja limpa)
    CREATE TEMP TABLE IF NOT EXISTS tmp_import_jsonl (linha text);
    TRUNCATE tmp_import_jsonl;

    -- 2. Importa o arquivo dinamicamente usando EXECUTE
    -- O EXECUTE é necessário para concatenar o parâmetro do caminho
    EXECUTE format('COPY tmp_import_jsonl (linha) FROM %L WITH (FORMAT csv, quote e''\x01'', delimiter e''\x02'')', p_caminho_arquivo);

    -- 3. Inserção dos dados
    SELECT 
        (SELECT id_dataset FROM datasets WHERE nome_dataset = 'OAB_Exams' LIMIT 1),
        COALESCE(linha::jsonb->>'statement', '') || E'\n\n' || COALESCE(linha::jsonb->>'turns', ''),
        (linha::jsonb->>'choices'),
        jsonb_build_object(
            'id_questao', (linha::jsonb->>'num')::int,
            'tipo', linha::jsonb->>'type',
            'edicao', linha::jsonb->>'edition',
            'ano', linha::jsonb->>'year',
            'especialidade', linha::jsonb->>'category',
            'dificuldade', linha::jsonb->>'level',
            'peca', COALESCE(linha::jsonb->>'brief', ''),
            'pessoa', linha::jsonb->>'system'
        )
    FROM tmp_import_jsonl
    WHERE linha LIKE '{%}';

    -- 3: Excluir a tabela temporária ao final para liberar memória
    DROP TABLE tmp_import_jsonl;

    RAISE NOTICE 'Importação concluída com sucesso a partir de %', p_caminho_arquivo;
END;
$$;


ALTER PROCEDURE public.importar_perguntas_abertas(IN p_caminho_arquivo text) OWNER TO postgres;

--
-- Name: importar_perguntas_fechadas(text); Type: PROCEDURE; Schema: public; Owner: postgres
--

CREATE PROCEDURE public.importar_perguntas_fechadas(IN p_caminho_arquivo text)
    LANGUAGE plpgsql
    AS $$
BEGIN
    -- 1. Criar/Limpar tabela temporária
    -- Nota: Tabelas temporárias duram apenas a sessão, mas o IF NOT EXISTS garante segurança
    CREATE TEMP TABLE IF NOT EXISTS tmp_import_jsonl (linha text);
    TRUNCATE tmp_import_jsonl;

    -- 2. Importa o arquivo usando SQL Dinâmico para aceitar o parâmetro
    EXECUTE format(
        'COPY tmp_import_jsonl (linha) FROM %L WITH (FORMAT csv, quote e''\x01'', delimiter e''\x02'')', 
        p_caminho_arquivo
    );

    -- 3. Inserção dos dados
    SELECT 
        (SELECT id_dataset FROM datasets WHERE nome_dataset = 'OAB_Exams' LIMIT 1),
        -- Composição do enunciado
        COALESCE(linha::jsonb->>'question', ''),
        linha::jsonb->>'answer',
        jsonb_build_object(
            'id_questao', (linha::jsonb->>'num')::int,
            'tipo', linha::jsonb->>'type',
            'edicao', linha::jsonb->>'edition',
            'ano', (linha::jsonb->>'year')::int, -- Cast para int se necessário
            'especialidade', linha::jsonb->>'category',
            'alternativas', linha::jsonb->'choices' -- Removido aspas para manter como objeto/array jsonb
        )
    FROM tmp_import_jsonl
    WHERE linha LIKE '{%}';

    -- Excluir tabela temporária
    DROP TABLE tmp_import_jsonl;
    
    RAISE NOTICE 'Importação do arquivo % concluída com sucesso.', p_caminho_arquivo;
END;
$$;


ALTER PROCEDURE public.importar_perguntas_fechadas(IN p_caminho_arquivo text) OWNER TO postgres;

--
-- Name: importar_respostas(text, text); Type: PROCEDURE; Schema: public; Owner: postgres
--

CREATE PROCEDURE public.importar_respostas(IN p_caminho_arquivo text, IN p_tipo_pergunta text)
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_linhas_inseridas INTEGER;
BEGIN
    -- 1. Validação do Parâmetro de Tipo
    IF p_tipo_pergunta NOT IN ('Aberta', 'Fechada') THEN
        RAISE EXCEPTION 'Tipo inválido: %. Use "Aberta" ou "Fechada".', p_tipo_pergunta;
    END IF;

    -- 2. Gestão da Tabela Temporária
    -- Criamos duas tabelas: uma para o COPY (text) e outra processada (jsonb)
    DROP TABLE IF EXISTS tmp_carga_bruta;
    CREATE TEMP TABLE tmp_carga_bruta (linha text);

    -- 3. Carga do arquivo para texto puro
    EXECUTE format(
        'COPY tmp_carga_bruta (linha) FROM %L WITH (FORMAT csv, quote e''\x01'', delimiter e''\x02'')', 
        p_caminho_arquivo
    );

    -- 4. Conversão para JSONB em uma tabela estruturada
    -- Isso elimina o erro de "operator does not exist" pois a coluna será nativamente jsonb
    DROP TABLE IF EXISTS tmp_dados_json;
    CREATE TEMP TABLE tmp_dados_json AS 
    SELECT linha::jsonb AS dados FROM tmp_carga_bruta;

    -- 5. Processamento e Inserção
        id_pergunta, 
        id_modelo, 
        texto_resposta, 
        tempo_inferencia_ms, 
        data_geracao
    )
    SELECT 
        p.id_pergunta,
        COALESCE(
            (NULLIF(tj.dados->>'id_modelo', ''))::INTEGER, 
            m.id_modelo
        ),
        (tj.dados->>'response')::TEXT,
        (tj.dados->>'time')::FLOAT,
        to_timestamp(tj.dados->>'generation', 'DD/MM/YYYY HH24:MI:SS')
    FROM tmp_dados_json tj
    INNER JOIN perguntas p ON 
        (p.metadados->>'id_questao') = (tj.dados->>'id_questao')
        AND (p.metadados->>'tipo') = p_tipo_pergunta
    LEFT JOIN modelos m ON 
        m.nome_modelo = (tj.dados->>'model_name')
    WHERE 
        -- Garante que temos um ID de modelo válido
        COALESCE((NULLIF(tj.dados->>'id_modelo', ''))::INTEGER, m.id_modelo) IS NOT NULL;

    -- 6. Feedback
    GET DIAGNOSTICS v_linhas_inseridas = ROW_COUNT;
    
    RAISE NOTICE 'Sucesso: % registros inseridos (Tipo: %).', 
                 v_linhas_inseridas, p_tipo_pergunta;

    -- Limpeza
    DROP TABLE IF EXISTS tmp_carga_bruta;
    DROP TABLE IF EXISTS tmp_dados_json;

EXCEPTION
    WHEN OTHERS THEN
        -- Limpeza em caso de erro
        DROP TABLE IF EXISTS tmp_carga_bruta;
        DROP TABLE IF EXISTS tmp_dados_json;
        RAISE EXCEPTION 'Erro processando arquivo: % (SQLSTATE: %)', SQLERRM, SQLSTATE;
END;
$$;


