--
-- Name: vw_avaliacoes_completas; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.vw_avaliacoes_completas AS
 SELECT aj.id_avaliacao,
    d.nome_dataset,
    d.dominio,
    p.enunciado,
    p.resposta_ouro,
    mc.nome_modelo AS modelo_candidato,
    mc.versao AS versao_candidato,
    mc.parametro_precisao,
    r.texto_resposta,
    r.tempo_inferencia_ms,
    r.data_geracao AS data_upload,
    mj.nome_modelo AS modelo_juiz,
    aj.nota_atribuida,
    COALESCE(aj.nota_humana, r.nota_humana) AS nota_humana,
    aj.chain_of_thought,
    aj.tokens_prompt,
    aj.tokens_completion,
    aj.data_avaliacao
   FROM (((((public.avaliacoes_juiz aj
     JOIN public.respostas_atividade_1 r ON ((r.id_resposta = aj.id_resposta_ativa1)))
     JOIN public.perguntas p ON ((p.id_pergunta = r.id_pergunta)))
     JOIN public.datasets d ON ((d.id_dataset = p.id_dataset)))
     JOIN public.modelos mc ON ((mc.id_modelo = r.id_modelo)))
     JOIN public.modelos mj ON ((mj.id_modelo = aj.id_modelo_juiz)));


ALTER VIEW public.vw_avaliacoes_completas OWNER TO postgres;

